QRCodeBuffer.pattern.set = function set(buffer, x_absolute, y_absolute , pattern){
  const size = Math.sqrt(pattern.length);

  for(let y = 0; y < size; y++){
    for (let x = 0; x < size; x++){
      QRCodeBuffer.bit.set.call(this, buffer, x_absolute + x, y_absolute + y, pattern[y * size + x]);
    }
  }
}

