  QRCodeBuffer.pattern.set.call(this, buffer, 0, this.size - 8, QRCodeBuffer.pattern.finder.bottom_left);

  for(let position of QRCodeBuffer.positions[this.version]){
    QRCodeBuffer.pattern.set.call(this, buffer, position.x - 2, position.y - 2, QRCodeBuffer.pattern.alignment);
  }
